+                    return Err(OptimizerError::InvalidNode(
+                        "value tensor for ConstantOfShape is empty".to_string(),
+                    ));
+                }
+                Ok(OutputTensor::I64(vec![fd[0]; element_count]))
+            }
+            ScalarType::I32 => {
+                let fd = constant_value_tensor.get_int32_data();
