+			if (d_{{ loop.index0 }} < {{ pad.copy_start }}u) {
+				pad = true;
+			}
+			if (d_{{ loop.index0 }} > {{ pad.end_pad_start }}u) {
+				pad = true;
+			}
+		{% endfor %}
+
+		if (pad) {
+			output_0.data[gidx] = Scalar({{ constant_value }});
+		} else {
+			let index = 
+				{%- for chunk in i_chunks | first -%}
+					{%- if not loop.first %}
+						+
+					{%- endif -%}
+					id_{{ loop.index0 }} * {{ chunk }}u
+				{%- endfor -%}
+			;
