+        Some(shape(&[2, 3, 4, 5])),
+    );
+
+    assert_eq!(
+        Shape::multi_broadcast(&[shape(&[4, 5]), shape(&[2, 3, 4, 5])]),
+        Some(shape(&[2, 3, 4, 5])),
