+        vec![tensor("Y", &[4, 3, 2])],
+        vec![],
+        vec![
+            node(
+                vec!["X"],
+                vec!["Y"],
+                "Transpose",
+                "Transpose",
+                vec![attribute("perm", vec![2, 1, 0])],
+            ),
+            node(
+                vec!["Y"],
+                vec!["Z"],
+                "Transpose",
+                "Transpose",
+                vec![attribute("perm", vec![2, 1, 0])],
+            ),
+        ],
+    ));
+
+    let session =
+        pollster::block_on(wonnx::Session::from_model(model)).expect("session did not create");
+    let result = pollster::block_on(session.run(input_data)).unwrap();
+
+    assert_eq!(result["Z"], data);
+}
